+fn sanitize_markdown_dest_url(dest_url: CowStr<'_>) -> CowStr<'_> {
+    let lower = dest_url
+        .trim()
+        .chars()
+        .filter(|ch| !ch.is_ascii_whitespace() && !ch.is_ascii_control())
+        .collect::<String>()
+        .to_lowercase();
+    if lower.starts_with("javascript:")
+        || lower.starts_with("vbscript:")
+        || lower.starts_with("data:")
+    {
+        "#".into()
+    } else {
+        dest_url
+    }
+}
